/* adc_interface.c */
#include "stm32f4xx_hal.h"

static volatile uint32_t s_adc_val = 0;

void HAL_ADC_ConvCpltCallback(ADC_HandleTypeDef* hadc) {
    if (hadc->Instance == ADC1) {
        // 只有在完成中断时才同步一次全局状态
        s_adc_val = HAL_ADC_GetValue(hadc);
    }
}

// 给外部提供的只读接口
uint32_t ADC_GetLatestValue(void) {
    uint32_t val;
    __disable_irq(); // 保护数据一致性，防止中断中途修改
    val = s_adc_val;
    __enable_irq();
    return val;
}

// 演示：防范全局指针空悬
static int *g_ptr = NULL;
void Data_Update(int *new_data) {
    if (new_data == NULL) return; // 修复：必须检查
    g_ptr = new_data;
}

